var GoAnalyzer = class extends BaseAnalyzer {
  id = "go";
  name = "Go";
  filePatterns = ["go.mod", "go.sum"];
  async analyze(files, _projectRoot) {
    const technologies = [];
    const analyzedFiles = [];
    const goModEntry = findFileEntry(files, "go.mod");
    if (!goModEntry) return { technologies, analyzedFiles };
    analyzedFiles.push(goModEntry.path);
    const versionMatch = goModEntry.content.match(/^go\s+(\d+\.\d+)/m);
    const goVersion = versionMatch?.[1];
    technologies.push({
      id: "go",
      name: "Go",
      category: "language",
      version: goVersion,
      majorVersion: goVersion ? parseInt(goVersion.split(".")[0], 10) : void 0,
      confidence: 95,
      evidence: [{ source: goModEntry.path, type: "manifest", description: `go.mod found (Go ${goVersion ?? "unknown"})`, weight: 95 }],
      profileIds: ["languages/go"]
    });
    const frameworkPatterns = [
      { pattern: "github.com/gin-gonic/gin", id: "gin", name: "Gin", profiles: ["frameworks/gin"] },
      { pattern: "github.com/labstack/echo", id: "echo", name: "Echo", profiles: ["frameworks/echo"] },
      { pattern: "github.com/gofiber/fiber", id: "fiber", name: "Fiber", profiles: ["frameworks/fiber"] },
      { pattern: "github.com/gorilla/mux", id: "gorilla-mux", name: "Gorilla Mux", profiles: [] }
    ];
    const requireDeps = this.extractRequireDeps(goModEntry.content);
    for (const fw of frameworkPatterns) {
      if (requireDeps.includes(fw.pattern)) {
        technologies.push({
          id: fw.id,
          name: fw.name,
          category: "framework",
          confidence: 90,
          evidence: [{ source: goModEntry.path, type: "manifest", description: `Found "${fw.pattern}" in dependencies`, weight: 90, trackedPackage: fw.pattern }],
          parentId: "go",
          profileIds: fw.profiles
        });
      }
    }
    return { technologies, analyzedFiles };
  }
  /** Extract dependency lines from require blocks and single-line requires, excluding comments and replace blocks */
  extractRequireDeps(goMod) {
    const lines = goMod.split("\n");
    const depLines = [];
    let inRequireBlock = false;
    let inReplaceBlock = false;
    for (const line of lines) {
      const trimmed = line.trim();
      if (trimmed.startsWith("//")) continue;
      if (/^replace\s*\(/.test(trimmed)) {
        inReplaceBlock = true;
        continue;
      }
      if (inReplaceBlock && trimmed === ")") {
        inReplaceBlock = false;
        continue;
      }
      if (inReplaceBlock) continue;
      if (/^require\s*\(/.test(trimmed)) {
        inRequireBlock = true;
        continue;
      }
      if (inRequireBlock && trimmed === ")") {
        inRequireBlock = false;
        continue;
      }
      if (inRequireBlock) depLines.push(trimmed);
      if (/^require\s+\S/.test(trimmed)) depLines.push(trimmed.replace(/^require\s+/, ""));
    }
    return depLines.join("\n");
  }
};

