var DotnetAnalyzer = class extends BaseAnalyzer {
  id = "dotnet";
  name = ".NET";
  filePatterns = ["*.csproj", "*.sln", "*.fsproj"];
  async analyze(files, _projectRoot) {
    const technologies = [];
    const analyzedFiles = [];
    for (const [filePath, content] of files) {
      if (filePath.endsWith(".csproj") || filePath.endsWith(".fsproj")) {
        analyzedFiles.push(filePath);
        const lang = filePath.endsWith(".fsproj") ? "fsharp" : "csharp";
        const langName = lang === "fsharp" ? "F#" : "C#";
        if (!technologies.some((t2) => t2.id === lang)) {
          technologies.push({
            id: lang,
            name: langName,
            category: "language",
            confidence: 95,
            evidence: [{ source: filePath, type: "manifest", description: `${filePath} found`, weight: 95 }],
            profileIds: lang === "csharp" ? ["languages/csharp"] : []
          });
        }
        if (!content) continue;
        try {
          const parsed = parseXml(content, filePath);
          const projStr = JSON.stringify(parsed);
          if (projStr.includes("Microsoft.AspNetCore") || projStr.includes("Microsoft.NET.Sdk.Web")) {
            if (!technologies.some((t2) => t2.id === "aspnet")) {
              technologies.push({
                id: "aspnet",
                name: "ASP.NET Core",
                category: "framework",
                confidence: 90,
                evidence: [{ source: filePath, type: "manifest", description: "ASP.NET Core SDK reference found", weight: 90 }],
                profileIds: []
              });
            }
          }
          const tfMatches = [...projStr.matchAll(/net(?:coreapp)?(\d+)\.\d+/g)];
          if (tfMatches.length > 0) {
            let bestMatch = tfMatches[0];
            let bestMajor = parseInt(bestMatch[1], 10);
            for (const m2 of tfMatches.slice(1)) {
              const major = parseInt(m2[1], 10);
              if (major > bestMajor) {
                bestMatch = m2;
                bestMajor = major;
              }
            }
            const dotnetTech = technologies.find((t2) => t2.id === lang);
            if (dotnetTech) {
              dotnetTech.version = bestMatch[0];
              dotnetTech.majorVersion = bestMajor;
            }
          }
        } catch {
        }
      }
      if (filePath.endsWith(".sln")) {
        analyzedFiles.push(filePath);
      }
    }
    return { technologies, analyzedFiles };
  }
};

