import path7 from "path";
var DockerAnalyzer = class extends BaseAnalyzer {
  id = "docker";
  name = "Docker";
  filePatterns = [
    "Dockerfile",
    "Dockerfile.*",
    "docker-compose.yml",
    "docker-compose.yaml",
    "compose.yml",
    "compose.yaml"
  ];
  async analyze(files, _projectRoot) {
    const technologies = [];
    const analyzedFiles = [];
    let hasDockerfile = false;
    let hasCompose = false;
    let multiStageFile;
    let multiStageCount = 0;
    let emittedMicroservicesHint = false;
    for (const [filePath, content] of files) {
      const basename2 = path7.basename(filePath);
      if (basename2.startsWith("Dockerfile")) {
        analyzedFiles.push(filePath);
        hasDockerfile = true;
        const stageCount = (content.match(/^FROM\s+/gm) ?? []).length;
        if (stageCount > 1) {
          multiStageFile = filePath;
          multiStageCount = stageCount;
        }
      } else if (basename2.includes("compose")) {
        analyzedFiles.push(filePath);
        hasCompose = true;
        const servicesMatch = content.match(/^services:\s*\n((?:\s+\S[^\n]*\n?)*)/m);
        let serviceCount = 0;
        if (servicesMatch?.[1]) {
          const rawIndent = servicesMatch[1].match(/^(\s+)/)?.[1]?.length ?? 2;
          const firstIndent = Math.min(rawIndent, 32);
          const indentPattern = new RegExp(`^\\s{${firstIndent}}[a-zA-Z_][\\w-]*:`, "gm");
          serviceCount = (servicesMatch[1].match(indentPattern) ?? []).length;
        }
        if (serviceCount > 3 && !emittedMicroservicesHint) {
          emittedMicroservicesHint = true;
          technologies.push({
            id: "microservices-hint",
            name: "Microservices (hint)",
            category: "infra",
            confidence: 60,
            evidence: [{
              source: filePath,
              type: "content",
              description: `${serviceCount} services in docker-compose suggest microservices`,
              weight: 60
            }],
            profileIds: []
          });
        }
      }
    }
    if (hasDockerfile || hasCompose) {
      const dockerTech = {
        id: "docker",
        name: "Docker",
        category: "infra",
        confidence: 95,
        evidence: [{
          source: analyzedFiles[0],
          type: "config-file",
          description: `Docker files found: ${analyzedFiles.join(", ")}`,
          weight: 95
        }],
        profileIds: ["infra/docker"]
      };
      if (multiStageFile && multiStageCount > 1) {
        dockerTech.evidence.push({
          source: multiStageFile,
          type: "content",
          description: `Multi-stage build detected (${multiStageCount} stages)`,
          weight: 5
        });
      }
      technologies.unshift(dockerTech);
    }
    return { technologies, analyzedFiles };
  }
};

