        content: `# Python Project Scaffold Skill

## Scaffold Steps

### 1. Create Directory Structure
\`\`\`
project-name/
  pyproject.toml
  README.md
  src/
    package_name/
      __init__.py
      py.typed           # PEP 561 marker for type stubs
  tests/
    __init__.py
    conftest.py
    unit/
      __init__.py
    integration/
      __init__.py
\`\`\`

### 2. Minimal pyproject.toml
\`\`\`toml
[project]
name = "package-name"
version = "0.1.0"
description = "Short description"
requires-python = ">=3.11"
dependencies = []

[project.optional-dependencies]
dev = [
    "pytest>=8.0",
    "pytest-cov>=5.0",
    "pytest-asyncio>=0.23",
    "mypy>=1.10",
    "ruff>=0.4",
]

[build-system]
requires = ["hatchling"]
build-backend = "hatchling.build"

[tool.ruff]
line-length = 88
target-version = "py311"

[tool.ruff.lint]
select = ["E", "F", "W", "I", "N", "UP", "B", "A", "C4", "SIM", "TCH", "RUF"]

[tool.mypy]
python_version = "3.11"
strict = true

[tool.pytest.ini_options]
testpaths = ["tests"]
asyncio_mode = "auto"
\`\`\`

### 3. Initial __init__.py
\`\`\`python
"""Package short description."""

from __future__ import annotations

__all__: list[str] = []
\`\`\`

### 4. conftest.py
\`\`\`python
"""Shared test fixtures."""

from __future__ import annotations

import pytest
\`\`\`

### 5. Install in Development Mode
\`\`\`bash
# With pip
pip install -e ".[dev]"

# With uv (faster)
uv pip install -e ".[dev]"
\`\`\`
`
