import path17 from "path";
async function generateExternalTools(config2, projectRoot) {
  const files = [];
  for (const tool of config2.externalTools) {
    const file = await generateToolConfig(tool, projectRoot);
    if (file) files.push(file);
  }
  return files;
}
async function generateToolConfig(tool, projectRoot) {
  const filePath = path17.join(projectRoot, tool.filePath);
  assertPathWithin(filePath, projectRoot);
  switch (tool.mergeStrategy) {
    case "create-only": {
      const existingRaw = await readFileOrNull(filePath);
      if (existingRaw !== null) return null;
      return {
        path: filePath,
        content: JSON.stringify(tool.config, null, 2) + "\n"
      };
    }
    case "align": {
      const existingRaw = await readFileOrNull(filePath);
      if (existingRaw === null) {
        return {
          path: filePath,
          content: JSON.stringify(tool.config, null, 2) + "\n"
        };
      }
      let existing;
      try {
        existing = JSON.parse(existingRaw);
      } catch {
        return null;
      }
      const merged = deepmerge(tool.config, existing);
      return {
        path: filePath,
        content: JSON.stringify(merged, null, 2) + "\n"
      };
    }
    case "overwrite": {
      return {
        path: filePath,
        content: JSON.stringify(tool.config, null, 2) + "\n"
      };
    }
  }
}

