// src/mcp/tools/sync-config.ts
function registerSyncConfigTool(server2) {
  server2.tool(
    "sync_config",
    "Re-analyze project and update .claude/ configuration with three-way merge",
    { projectDir: external_exports.string().describe("Absolute path to the project root directory") },
    async ({ projectDir }) => {
      if (!await fileExists(projectDir)) {
        return {
          content: [{ type: "text", text: JSON.stringify({ error: "DIRECTORY_NOT_FOUND", message: `Directory not found: ${projectDir}` }) }],
          isError: true
        };
      }
      try {
        const engine = new DivergerEngine();
        const { results: mergeResults, pendingMeta, oldMeta } = await engine.sync({
          projectRoot: projectDir,
          options: { output: "quiet", force: true, dryRun: false, targetDir: projectDir }
        });
        const writtenFiles = [];
        for (const result of mergeResults) {
          if ((result.outcome === "auto-apply" || result.outcome === "merged") && result.content) {
            await writeFileAtomic(result.path, result.content);
            writtenFiles.push({ path: result.path, content: result.content });
          }
        }
        const conflicts = mergeResults.filter((r2) => r2.outcome === "conflict");
        for (const conflict of conflicts) {
          if (conflict.content) {
            await writeFileAtomic(conflict.path, conflict.content);
            writtenFiles.push({ path: conflict.path, content: conflict.content });
          }
        }
        const finalMeta = finalizeMetaAfterWrite(pendingMeta, writtenFiles, oldMeta, projectDir);
        await saveMeta(projectDir, finalMeta);
        const summary = {
          skip: mergeResults.filter((r2) => r2.outcome === "skip").length,
          autoApply: mergeResults.filter((r2) => r2.outcome === "auto-apply").length,
          keep: mergeResults.filter((r2) => r2.outcome === "keep").length,
          merged: mergeResults.filter((r2) => r2.outcome === "merged").length,
          conflict: mergeResults.filter((r2) => r2.outcome === "conflict").length,
          error: mergeResults.filter((r2) => r2.outcome === "error").length
        };
        return {
          content: [{
            type: "text",
            text: JSON.stringify({
              updated: mergeResults.filter((r2) => r2.outcome === "auto-apply" || r2.outcome === "merged").map((r2) => r2.path),
              conflicts: conflicts.map((r2) => ({
                path: r2.path,
                resolution: "auto-resolved (ours)"
              })),
              skipped: mergeResults.filter((r2) => r2.outcome === "skip" || r2.outcome === "keep").map((r2) => r2.path),
              summary
            })
          }]
        };
      } catch (err) {
        return {
          content: [{ type: "text", text: JSON.stringify({ error: "SYNC_ERROR", message: extractErrorMessage(err) }) }],
          isError: true
        };
      }
    }
  );
}

// src/mcp/types.ts
function layerName(layer) {
  switch (layer) {
    case 0:
      return "base";
    case 10:
      return "language";
    case 20:
      return "framework";
    case 30:
      return "testing";
    case 40:
      return "infra";
    default:
      return "unknown";
  }
}
function toProfileSummary(profile) {
  return {
    id: profile.id,
    name: profile.name,
    layer: profile.layer,
    layerName: layerName(profile.layer),
    technologyIds: profile.technologyIds,
    ...profile.dependsOn ? { dependsOn: profile.dependsOn } : {}
  };
}

// src/mcp/tools/list-profiles.ts
function registerListProfilesTool(server2) {
  server2.tool(
    "list_profiles",
    "List all available diverger-claude profiles (optionally filtered by layer)",
    {
      layer: external_exports.number().optional().describe("Filter by layer number: 0=base, 10=language, 20=framework, 30=testing, 40=infra")
    },
    async ({ layer }) => {
      const allProfiles = getAllProfiles();
      const filtered = layer !== void 0 ? allProfiles.filter((p2) => p2.layer === layer) : allProfiles;
      const summaries = filtered.map(toProfileSummary);
      return {
        content: [{
          type: "text",
          text: JSON.stringify({
            profiles: summaries,
            count: summaries.length
          })
        }]
      };
    }
  );
}

// src/mcp/tools/get-profile.ts
function registerGetProfileTool(server2) {
  server2.tool(
    "get_profile",
    "Get full details of a specific diverger-claude profile by ID",
    { profileId: external_exports.string().describe('Profile ID (e.g. "languages/typescript", "base/universal")') },
    async ({ profileId }) => {
      const profile = getProfileById(profileId);
      if (!profile) {
        return {
          content: [{ type: "text", text: JSON.stringify({ error: "PROFILE_NOT_FOUND", message: `Profile not found: ${profileId}` }) }],
          isError: true
        };
      }
      return {
        content: [{ type: "text", text: JSON.stringify(profile) }]
      };
    }
  );
}

